import{_ as i,o as e,c as r,ag as l}from"./chunks/framework.CAXxHpAX.js";const p=JSON.parse('{"title":"Windsurf 配置","description":"","frontmatter":{},"headers":[],"relativePath":"tools/windsurf.md","filePath":"tools/windsurf.md"}'),o={name:"tools/windsurf.md"};function t(s,a,n,d,h,u){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="windsurf-配置" tabindex="-1">Windsurf 配置 <a class="header-anchor" href="#windsurf-配置" aria-label="Permalink to &quot;Windsurf 配置&quot;">​</a></h1><p>Windsurf 是一个 AI 代码编辑器，提供内置 AI 编程助手功能。</p><h2 id="这是什么工具" tabindex="-1">这是什么工具 <a class="header-anchor" href="#这是什么工具" aria-label="Permalink to &quot;这是什么工具&quot;">​</a></h2><p>Windsurf 是一个独立的代码编辑器，内置 AI 功能。它支持 BYOK（Bring Your Own Key）模式，允许使用自定义 API Key。</p><h2 id="配置前需要准备什么" tabindex="-1">配置前需要准备什么 <a class="header-anchor" href="#配置前需要准备什么" aria-label="Permalink to &quot;配置前需要准备什么&quot;">​</a></h2><ul><li>有效的 API Key</li><li>默认 Base URL：<code>https://api.1010101.asia/</code></li></ul><h2 id="从哪里打开配置入口" tabindex="-1">从哪里打开配置入口 <a class="header-anchor" href="#从哪里打开配置入口" aria-label="Permalink to &quot;从哪里打开配置入口&quot;">​</a></h2><p>Windsurf 的 API Key 配置入口：</p><ol><li>打开 Windsurf</li><li>进入订阅设置页面</li><li>找到&quot;Provider API Keys&quot;页面</li></ol><p>或：</p><ol><li>打开设置</li><li>查找&quot;Provider&quot;或&quot;API Keys&quot;相关设置</li></ol><h2 id="最短完整配置步骤" tabindex="-1">最短完整配置步骤 <a class="header-anchor" href="#最短完整配置步骤" aria-label="Permalink to &quot;最短完整配置步骤&quot;">​</a></h2><ol><li>进入&quot;Provider API Keys&quot;页面</li><li>选择要配置的 Provider</li><li>在 <code>API Key</code> 字段中输入你的 API Key</li><li>如有 <code>Base URL</code> 或 <code>Endpoint</code> 字段，输入：<code>https://api.1010101.asia/</code></li><li>保存设置</li></ol><h2 id="配置示例" tabindex="-1">配置示例 <a class="header-anchor" href="#配置示例" aria-label="Permalink to &quot;配置示例&quot;">​</a></h2><h3 id="provider-api-keys-设置" tabindex="-1">Provider API Keys 设置 <a class="header-anchor" href="#provider-api-keys-设置" aria-label="Permalink to &quot;Provider API Keys 设置&quot;">​</a></h3><ul><li><strong>Provider</strong>: 选择对应 Provider</li><li><strong>API Key</strong>: <code>sk-xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx</code></li><li><strong>Base URL</strong>: <code>https://api.1010101.asia/</code>（如有此字段）</li></ul><h2 id="如何验证生效" tabindex="-1">如何验证生效 <a class="header-anchor" href="#如何验证生效" aria-label="Permalink to &quot;如何验证生效&quot;">​</a></h2><ol><li>在 Windsurf 中使用 AI 功能</li><li>发送一个简单请求</li><li>如果收到正常回复，说明配置成功</li></ol><p>或：</p><ol><li>在模型选择中查看是否有 BYOK 标识</li><li>选择 BYOK 模型进行测试</li></ol><h2 id="常见报错与排查" tabindex="-1">常见报错与排查 <a class="header-anchor" href="#常见报错与排查" aria-label="Permalink to &quot;常见报错与排查&quot;">​</a></h2><h3 id="_401-unauthorized" tabindex="-1">401 Unauthorized <a class="header-anchor" href="#_401-unauthorized" aria-label="Permalink to &quot;401 Unauthorized&quot;">​</a></h3><p><strong>原因</strong>：API Key 错误或无效</p><p><strong>排查</strong>：</p><ul><li>检查 API Key 是否正确</li><li>检查 API Key 是否有多余空格</li><li>确认 API Key 是否已过期或被撤销</li></ul><h3 id="_404-not-found" tabindex="-1">404 Not Found <a class="header-anchor" href="#_404-not-found" aria-label="Permalink to &quot;404 Not Found&quot;">​</a></h3><p><strong>原因</strong>：Base URL 错误</p><p><strong>排查</strong>：</p><ul><li>检查 Base URL 是否正确</li><li>确认 Base URL 格式符合要求</li><li>检查网络连接是否正常</li></ul><h3 id="missing-api-key-错误" tabindex="-1">Missing API Key 错误 <a class="header-anchor" href="#missing-api-key-错误" aria-label="Permalink to &quot;Missing API Key 错误&quot;">​</a></h3><p><strong>原因</strong>：未正确设置 API Key</p><p><strong>排查</strong>：</p><ul><li>确认已在&quot;Provider API Keys&quot;页面填写 API Key</li><li>检查 API Key 是否保存成功</li></ul><h3 id="byok-模型不可用" tabindex="-1">BYOK 模型不可用 <a class="header-anchor" href="#byok-模型不可用" aria-label="Permalink to &quot;BYOK 模型不可用&quot;">​</a></h3><p><strong>原因</strong>：BYOK 仅支持特定模型</p><p><strong>排查</strong>：</p><ul><li>查看 Windsurf 文档确认 BYOK 支持的模型列表</li><li>确认当前选择的模型支持 BYOK</li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><h3 id="byok-限制" tabindex="-1">BYOK 限制 <a class="header-anchor" href="#byok-限制" aria-label="Permalink to &quot;BYOK 限制&quot;">​</a></h3><p>Windsurf 的 BYOK 功能有以下限制：</p><ul><li>仅支持特定模型</li><li>仅适用于个人用户</li><li>需要有效的 API Key</li></ul><h3 id="base-url-配置" tabindex="-1">Base URL 配置 <a class="header-anchor" href="#base-url-配置" aria-label="Permalink to &quot;Base URL 配置&quot;">​</a></h3><p>Windsurf 的公开文档对自定义 Base URL 的说明较少。如果设置中没有 Base URL 字段，可能需要：</p><ul><li>使用环境变量（如支持）</li><li>参考 Windsurf 社区或官方支持</li></ul><h3 id="模型选择" tabindex="-1">模型选择 <a class="header-anchor" href="#模型选择" aria-label="Permalink to &quot;模型选择&quot;">​</a></h3><p>在 Windsurf 中，BYOK 模型通常会有特殊标识。选择带有 BYOK 标识的模型以使用自定义 API Key。</p><h3 id="订阅状态" tabindex="-1">订阅状态 <a class="header-anchor" href="#订阅状态" aria-label="Permalink to &quot;订阅状态&quot;">​</a></h3><p>某些功能可能需要订阅。请确认你的 Windsurf 订阅状态支持 BYOK 功能。</p><h3 id="版本差异" tabindex="-1">版本差异 <a class="header-anchor" href="#版本差异" aria-label="Permalink to &quot;版本差异&quot;">​</a></h3><p>Windsurf 的设置界面可能因版本更新而变化。本页面基于 2026 年 5 月的信息，如有变化请以应用内实际界面为准。</p>',50)])])}const P=i(o,[["render",t]]);export{p as __pageData,P as default};
